const raw = ($json.content || []).find(b => b.type === 'text')?.text || '';

const clean = raw.trim().startsWith('```')
  ? raw.trim().replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
  : raw.trim();

if (!clean || clean.length < 100) {
  throw new Error('Claude returned an unexpectedly short manuscript. Got: ' + clean.slice(0, 200));
}

const wordCount = clean.split(/\s+/).filter(w => w.length > 0).length;
const productId = $('Webhook Trigger').first().json.body.product_id;

return [{ json: { manuscript: clean, wordCount, productId } }];

const productId = $('Parse Manuscript').item.json.productId;
const wordCount = $('Parse Manuscript').item.json.wordCount;
const specRaw = $('Fetch Product Spec').all()[0]?.json || [];
const product = Array.isArray(specRaw) ? (specRaw[0] || {}) : specRaw;

const title       = product.name || product.title || 'Ebook';
const description = product.description || '';
const spec        = product.spec || {};
const chapterCount = spec.chapters
  ? spec.chapters.length
  : (spec.ebook && spec.ebook.chapters ? spec.ebook.chapters.length : 0);

const dateStr = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const html = '<!DOCTYPE html><html><body style="font-family:sans-serif;background:#0A0A0A;color:#fff;margin:0;padding:0">'
  + '<div style="max-width:640px;margin:0 auto;padding:32px 24px">'
  + '<p style="color:#C8F53A;font-size:12px;letter-spacing:2px;margin:0 0 8px">CIPHER STUDIO</p>'
  + '<h1 style="font-size:32px;color:#fff;margin:0 0 4px">Manuscript Complete</h1>'
  + '<p style="color:#666;margin:0 0 32px;font-size:14px">' + dateStr + '</p>'
  + '<div style="background:#111;border:1px solid #222;border-radius:8px;padding:24px;margin-bottom:24px">'
  + '<p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 8px">EBOOK MANUSCRIPT</p>'
  + '<h2 style="margin:0 0 12px;font-size:22px">' + title + '</h2>'
  + (description ? '<p style="color:#aaa;margin:0 0 16px;line-height:1.6">' + description + '</p>' : '')
  + '<p style="margin:0"><strong style="color:#C8F53A">' + Number(wordCount).toLocaleString() + ' words</strong>'
  + (chapterCount ? ' &nbsp;&middot;&nbsp; ' + chapterCount + ' chapters' : '')
  + '</p>'
  + '</div>'
  + '<div style="background:#111;border:1px solid #C8F53A;border-radius:8px;padding:20px;margin-bottom:24px">'
  + '<p style="color:#C8F53A;font-size:11px;letter-spacing:1px;margin:0 0 8px">PIPELINE STATUS</p>'
  + '<p style="color:#aaa;font-family:sans-serif;margin:0;line-height:1.6">The Ebook Designer Agent has been triggered and will produce the formatted PDF next. You\'ll receive another email when the PDF is ready.</p>'
  + '</div>'
  + '<p style="color:#444;font-size:12px;text-align:center">Supabase products table &nbsp;&middot;&nbsp; cipherstudio.co</p>'
  + '</div></body></html>';

return [{ json: {
  subject: 'Manuscript Written: ' + title + ' (' + Number(wordCount).toLocaleString() + ' words)',
  html
} }];
